async (params, browser) => {
  // Open Duolingo
  await browser.open(`https://www.duolingo.com/course/${params.language}/en`)

  // Wait for page
  await browser.waitForSelector('h1, .content, [class*="course"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim() || ''; const desc = document.querySelector('[class*="description"], p')?.textContent?.trim() || ''; const skills = []; document.querySelectorAll('[class*="skill"], [class*="unit"], li').forEach((el, i) => { if (i < 30) skills.push(el.textContent?.trim()?.slice(0, 100)); }); return { title, description: desc, skills, url: window.location.href };`)

  return result
}
